#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <ctime>
#include <cassert>
#include <iostream>
#include <sys/time.h>
#include <cuda_runtime.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define DEVICE   0
#define M_SEED   9

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) x = (x < (min)) ? (min) : (((x) > (max)) ? (max) : (x))
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

int platform_id_inuse = 0;
int device_id_inuse = 0;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static inline void tvsub(const struct timeval* newer, const struct timeval* older, struct timeval* out)
{
    out->tv_sec = newer->tv_sec - older->tv_sec;
    out->tv_usec = newer->tv_usec - older->tv_usec;
    if (out->tv_usec < 0) {
        out->tv_sec--;
        out->tv_usec += 1000000;
    }
}

static inline float tvms(const struct timeval* t)
{
    return t->tv_sec * 1000.0f + (float)t->tv_usec / 1000.0f;
}
#endif

#define CUDA_CHECK(call) \
    do { \
        cudaError_t _err = (call); \
        if (_err != cudaSuccess) { \
            fprintf(stderr, "CUDA error: %s\n", cudaGetErrorString(_err)); \
            exit(1); \
        } \
    } while (0)

__global__ void dynproc_kernel(int iteration,
                               const int* gpuWall,
                               const int* gpuSrc,
                               int* gpuResults,
                               int cols,
                               int rows,
                               int startStep,
                               int border,
                               int HALO_value,
                               int* outputBuffer)
{
    extern __shared__ int s[];
    int* prev = s;
    int* result_s = s + blockDim.x;

    int BLOCK_SIZE = (int)blockDim.x;
    int bx = (int)blockIdx.x;
    int tx = (int)threadIdx.x;

    int small_block_cols = BLOCK_SIZE - (iteration * HALO_value * 2);

    int blkX = (small_block_cols * bx) - border;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int xidx = blkX + tx;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

    int W = tx - 1;
    int E = tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool isValid = IN_RANGE(tx, validXmin, validXmax);

    if (IN_RANGE(xidx, 0, cols - 1)) {
        prev[tx] = gpuSrc[xidx];
    }

    __syncthreads();

    bool computed = false;
    for (int i = 0; i < iteration; i++) {
        computed = false;

        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
            computed = true;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);

            int index = cols * (startStep + i) + xidx;
            result_s[tx] = shortest + gpuWall[index];

            if (tx == 11 && i == 0) {
                int bufIndex = gpuSrc[xidx];
                outputBuffer[bufIndex] = 1;
            }
        }

        __syncthreads();

        if (i == iteration - 1) {
            break;
        }

        if (computed) {
            prev[tx] = result_s[tx];
        }
        __syncthreads();
    }

    if (computed) {
        gpuResults[xidx] = result_s[tx];
    }
}

void init(int argc, char** argv)
{
    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
            verbose = 1;
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    if (cols < 0 || rows < 0 || pyramid_height < 0) {
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v] [-p platform_id] [-d device_id] [-t device_type]\n", argv[0]);
        exit(0);
    }

    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++) {
        wall[n] = data + cols * n;
    }
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            wall[i][j] = rand() % 10;
        }
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

int main(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;
    int size = rows * cols;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    int device_count = 0;
    CUDA_CHECK(cudaGetDeviceCount(&device_count));
    if (device_count <= 0) {
        fprintf(stderr, "CUDA error: no devices found\n");
        return 1;
    }
    if (device_id_inuse < 0 || device_id_inuse >= device_count) {
        fprintf(stderr, "CUDA error: invalid device id %d\n", device_id_inuse);
        return 1;
    }
    CUDA_CHECK(cudaSetDevice(device_id_inuse));

    size_t gwsize = (size_t)rows * (size_t)cols;
    cudaFuncAttributes attr;
    CUDA_CHECK(cudaFuncGetAttributes(&attr, dynproc_kernel));

    size_t lwsize = (size_t)attr.maxThreadsPerBlock;
    if (lwsize == 0) {
        cout << "Error: kernel max work group size of zero!" << endl;
        return 1;
    }

    size_t howManyThreads = lwsize;
    if (lwsize > gwsize) {
        lwsize = gwsize;
        printf("Using %zu for local work size. \n", lwsize);
    } else {
        while (gwsize % howManyThreads != 0) {
            howManyThreads--;
        }
        if (verbose)
            printf("Max local threads is %zu. Using %zu for local work size. \n", lwsize, howManyThreads);
        lwsize = howManyThreads;
    }

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tvms(&tv);
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
    }

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    int* d_gpuWall = NULL;
    int* d_gpuResult[2] = {NULL, NULL};
    int* d_outputBuffer = NULL;

    size_t wall_bytes = (size > cols) ? sizeof(int) * (size_t)(size - cols) : 0;
    size_t result_bytes = (cols > 0) ? sizeof(int) * (size_t)cols : 0;
    size_t output_bytes = sizeof(int) * 16384ULL;

    if (wall_bytes > 0) CUDA_CHECK(cudaMalloc((void**)&d_gpuWall, wall_bytes));
    if (result_bytes > 0) {
        CUDA_CHECK(cudaMalloc((void**)&d_gpuResult[0], result_bytes));
        CUDA_CHECK(cudaMalloc((void**)&d_gpuResult[1], result_bytes));
    }
    CUDA_CHECK(cudaMalloc((void**)&d_outputBuffer, output_bytes));

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tvms(&tv);
#endif

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    if (wall_bytes > 0) CUDA_CHECK(cudaMemcpy(d_gpuWall, data + cols, wall_bytes, cudaMemcpyHostToDevice));
    if (result_bytes > 0) CUDA_CHECK(cudaMemcpy(d_gpuResult[0], data, result_bytes, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_outputBuffer, h_outputBuffer, output_bytes, cudaMemcpyHostToDevice));
#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time += tvms(&tv);
#endif

    int src = 1, final_ret = 0;
    dim3 block((unsigned int)lwsize);
    dim3 grid((unsigned int)(gwsize / lwsize));
    size_t shared_mem_bytes = sizeof(int) * lwsize * 2ULL;

    for (int t = 0; t < rows - 1; t += pyramid_height) {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows - t - 1);
        int theHalo = HALO;

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        dynproc_kernel<<<grid, block, shared_mem_bytes>>>(
            arg0,
            d_gpuWall,
            d_gpuResult[src],
            d_gpuResult[final_ret],
            cols,
            rows,
            t,
            borderCols,
            theHalo,
            d_outputBuffer
        );
        CUDA_CHECK(cudaGetLastError());
#ifdef TIMING
        CUDA_CHECK(cudaDeviceSynchronize());
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tvms(&tv);
#endif
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    if (result_bytes > 0) CUDA_CHECK(cudaMemcpy(result, d_gpuResult[final_ret], result_bytes, cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(h_outputBuffer, d_outputBuffer, sizeof(char) * 16384ULL, cudaMemcpyDeviceToHost));
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tvms(&tv);
#endif

    h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    if (d_gpuWall) CUDA_CHECK(cudaFree(d_gpuWall));
    if (d_gpuResult[0]) CUDA_CHECK(cudaFree(d_gpuResult[0]));
    if (d_gpuResult[1]) CUDA_CHECK(cudaFree(d_gpuResult[1]));
    if (d_outputBuffer) CUDA_CHECK(cudaFree(d_outputBuffer));

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tvms(&tv);
#endif

    delete[] data;
    delete[] wall;
    delete[] result;
    free(h_outputBuffer);

#ifdef TIMING
    gettimeofday(&tv_total_end, NULL);
    tvsub(&tv_total_end, &tv_total_start, &tv);
    total_time = tvms(&tv);

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return EXIT_SUCCESS;
}
